#include <iostream>
#include <vector>
#include <unordered_map>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <cstring>
#include <thread>
#include <atomic>

struct Player {
    int id;
    float x, y, z;
    float yaw, pitch;
    int health;
    bool isAlive;
};

struct Packet {
    int type;
    int playerId;
    float x, y, z;
    float yaw, pitch;
    int actionType;
    int targetId;
};

class GameServer {
private:
    int serverSocket;
    sockaddr_in serverAddr;
    std::unordered_map<int, Player> players;
    std::atomic<int> nextPlayerId{1};
    std::vector<Packet> packetQueue;

public:
    GameServer() {
        serverSocket = socket(AF_INET, SOCK_DGRAM, 0);
        serverAddr.sin_family = AF_INET;
        serverAddr.sin_port = htons(12345);
        serverAddr.sin_addr.s_addr = INADDR_ANY;
        bind(serverSocket, (struct sockaddr*)&serverAddr, sizeof(serverAddr));
    }

    void run() {
        std::thread packetProcessor(&GameServer::processPackets, this);
        packetProcessor.join();
    }

private:
    void processPackets() {
        while (true) {
            Packet packet;
            socklen_t addrLen = sizeof(sockaddr_in);
            recvfrom(serverSocket, &packet, sizeof(Packet), 0, (struct sockaddr*)&serverAddr, &addrLen);

            if (packet.type == 0) { // Player position update
                auto& player = players[packet.playerId];
                player.x = packet.x;
                player.y = packet.y;
                player.z = packet.z;
                player.yaw = packet.yaw;
                player.pitch = packet.pitch;
            } else if (packet.type == 1) { // Shooting action
                auto& shooter = players[packet.playerId];
                if (shooter.isAlive) {
                    auto& target = players[packet.targetId];
                    if (target.isAlive) {
                        target.health -= 25;
                        if (target.health <= 0) {
                            target.isAlive = false;
                        }
                    }
                }
            } else if (packet.type == 2) { // New player join
                Player newPlayer;
                newPlayer.id = nextPlayerId++;
                newPlayer.x = packet.x;
                newPlayer.y = packet.y;
                newPlayer.z = packet.z;
                newPlayer.yaw = packet.yaw;
                newPlayer.pitch = packet.pitch;
                newPlayer.health = 100;
                newPlayer.isAlive = true;
                players[newPlayer.id] = newPlayer;
            }
        }
    }
};

int main() {
    GameServer server;
    server.run();
    return 0;
}